class Solution:
    def constructProductMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        n, m = len(grid), len(grid[0])
        product = 1
        zero_count = 0
        zero_positions = []

        # First pass: compute total product and count zeros
        for i in range(n):
            for j in range(m):
                if grid[i][j] == 0:
                    zero_count += 1
                    zero_positions.append((i, j))
                else:
                    product *= grid[i][j]

        # Second pass: compute product matrix
        result = [[0] * m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if zero_count > 1:
                    result[i][j] = 0
                elif zero_count == 1 and (i, j) in zero_positions:
                    result[i][j] = 0
                else:
                    result[i][j] = product // grid[i][j] if grid[i][j] != 0 else 0

        # Apply modulo 12345
        mod = 12345
        for i in range(n):
            for j in range(m):
                result[i][j] %= mod

        return result
